const REQUIRED_STRING_FIELDS = [
  'robotName',
  'environment',
  'DBSchemaName',
  'DBTableNameAgents',
  'DBTableNameRecoveryTransactions',
  'DBTableNameBalanceTransactions',
  'DBTableNameBalanceMoves',
  'WFMDBSchema',
  'WFMSBaseURL',
  'MattermostAPIURL',
  'Mattermost1CChannelBaseURL',
  'MMCBotAlertChannel',
  'MMCBotProdNotificationsChannel',
  'GitBranch',
  'MappingsPath',
  'GitRawBaseURL',
];

const REQUIRED_NUMBER_FIELDS = [
  'DataRetentionMonthsTransactions',
  'DataRetentionMonthsPII',
  'BatchSizeMaxAgents',
  'BatchSizeMaxBytes',
];

const item = $input.first().json;
const missing = [];

for (const field of REQUIRED_STRING_FIELDS) {
  const value = item[field];
  if (value === undefined || value === null || String(value).trim() === '') {
    missing.push(field);
  }
}

for (const field of REQUIRED_NUMBER_FIELDS) {
  const value = item[field];
  if (value === undefined || value === null || Number.isNaN(Number(value))) {
    missing.push(field);
  }
}

if (missing.length > 0) {
  throw new Error(`System Error: Config validation failed. Missing fields: ${missing.join(', ')}`);
}

return [{ json: item }];
